defmodule Bank do
  use GenServer

  def start_link(initial_balance) do
    GenServer.start_link(__MODULE__, initial_balance, [])
  end

  def init(balance) do
    {:ok, balance}
  end

  def handle_call({:deposit, amount}, _from, balance) do
    new_balance = balance + amount
    {:reply, :ok, new_balance}
  end

  def handle_call({:withdraw, amount}, _from, balance) when balance >= amount do
    new_balance = balance - amount
    {:reply, :ok, new_balance}
  end

  def handle_call({:get_balance}, _from, balance) do
    {:reply, balance, balance}
  end

  def handle_cast({:update_balance, new_balance}, state) do
    {:noreply, new_balance}
  end

  def get_balance(pid) do
    GenServer.call(pid, {:get_balance})
  end

  def deposit(pid, amount) do
    GenServer.cast(pid, {:deposit, amount})
  end

  def withdraw(pid, amount) when is_pid(pid) and is_integer(amount) do
    GenServer.cast(pid, {:withdraw, amount})
  end

  def update_balance(pid, new_balance) do
    GenServer.cast(pid, {:update_balance, new_balance})
  end
end

defmodule BankTransaction do
  use GenServer

  @ets_table :bank_transactions

  def start_link() do
    :ets.new(@ets_table, [:named_table])
    GenServer.start_link(__MODULE__, nil, [])
  end

  def init(_) do
    {:ok, nil}
  end

  def handle_cast({:make_transaction, from_pid, to_pid, amount}, state) do
    balance = get_balance(from_pid)
    if balance >= amount do
      new_balance = balance - amount
      update_balance(from_pid, new_balance)

      deposit(to_pid, amount)
      withdraw(from_pid, amount)
    else
      IO.puts("Insufficient funds")
    end

    {:noreply, state}
  end

  defp get_balance(pid) do
    GenServer.call(pid, {:get_balance})
  end

  defp update_balance(pid, new_balance) do
    GenServer.cast(pid, {:update_balance, new_balance})
  end

  def make_transaction(from_pid, to_pid, amount) when is_pid(from_pid) and is_pid(to_pid) and is_integer(amount) do
    GenServer.cast(__MODULE__, {:make_transaction, from_pid, to_pid, amount})
  end
end